// Chat Preview button injector for Langfuse Session pages
// Renders tool calls and text in strict chronological order
(function() {
  'use strict';

  var CHAT_PREVIEW_BTN_ID = 'chat-preview-btn';
  var CHECK_INTERVAL = 2000;

  function isSessionPage() {
    return /\/project\/[^/]+\/sessions\/[^/]+/.test(location.pathname);
  }

  function getSessionId() {
    var m = location.pathname.match(/\/sessions\/([^/?]+)/);
    return m ? decodeURIComponent(m[1]) : null;
  }

  function getProjectId() {
    var m = location.pathname.match(/\/project\/([^/]+)/);
    return m ? m[1] : null;
  }

  function extractText(val) {
    if (!val) return '';
    if (typeof val === 'string') {
      try { return extractText(JSON.parse(val)); } catch(e) { return val; }
    }
    if (typeof val === 'object' && val !== null) {
      if (val.message) return String(val.message);
      if (val.content) return String(val.content);
      if (val.text) return String(val.text);
      if (Array.isArray(val)) {
        var last = val.filter(function(m){return m.role==='user'||m.role==='assistant'}).pop();
        if (last) return last.content || '';
        return val.map(function(v){return extractText(v)}).filter(Boolean).join('\n');
      }
      return JSON.stringify(val, null, 2);
    }
    return String(val);
  }

  function extractInputText(val) {
    if (!val) return '';
    if (typeof val === 'object' && val !== null && val.message) return String(val.message);
    return extractText(val);
  }

  function parseIfString(val) {
    if (typeof val === 'string') {
      try { return JSON.parse(val); } catch(e) { return val; }
    }
    return val;
  }

  function extractOutputEvents(val) {
    val = parseIfString(val);
    if (!val || typeof val !== 'object') return null;
    if (Array.isArray(val.events)) return val.events;
    return null;
  }

  function extractOutputFallback(val) {
    val = parseIfString(val);
    if (!val) return '';
    if (typeof val === 'object' && val !== null) {
      if (val.content) return String(val.content);
      if (val.events) return '';
    }
    return extractText(val);
  }

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function renderToolArgs(args) {
    if (!args) return '';
    if (typeof args === 'string') return escapeHtml(args);
    try { return escapeHtml(JSON.stringify(args, null, 2)); } catch(e) { return escapeHtml(String(args)); }
  }

  function buildPreviewHtml(sessionId, traces) {
    var metaParts = ['Session: ' + sessionId.slice(0,16) + '…', traces.length + ' traces'];
    var lastDate = '';
    var turnsHtml = '';

    traces.sort(function(a,b){ return new Date(a.timestamp) - new Date(b.timestamp); });

    for (var i = 0; i < traces.length; i++) {
      var trace = traces[i];
      var ts = new Date(trace.timestamp);
      var dateStr = ts.toLocaleDateString('zh-CN', {year:'numeric',month:'long',day:'numeric'});
      if (dateStr !== lastDate) {
        lastDate = dateStr;
        turnsHtml += '<div class="divider">' + escapeHtml(dateStr) + '</div>';
      }
      var timeStr = ts.toLocaleTimeString('zh-CN', {hour:'2-digit',minute:'2-digit',second:'2-digit'});
      var input = extractInputText(trace.input);

      if (input) {
        turnsHtml += '<div class="turn user"><div class="role-label">User</div><div class="bubble">' + escapeHtml(input) + '</div><div class="timestamp">' + escapeHtml(timeStr) + '</div></div>';
      }

      var events = extractOutputEvents(trace.output);
      if (events && events.length > 0) {
        turnsHtml += '<div class="turn assistant"><div class="role-label">Assistant</div>';
        for (var j = 0; j < events.length; j++) {
          var evt = events[j];
          if (evt.type === 'content' && evt.content) {
            turnsHtml += '<div class="bubble md">' + escapeHtml(evt.content) + '</div>';
          } else if (evt.type === 'tool_call') {
            var statusClass = evt.success === false ? 'tool-fail' : 'tool-ok';
            var elapsedStr = evt.elapsed_ms != null ? ' · ' + evt.elapsed_ms + 'ms' : '';
            turnsHtml += '<div class="tool-card ' + statusClass + '">';
            turnsHtml += '<div class="tool-header"><span class="tool-icon">' + (evt.success === false ? '✗' : '⚡') + '</span>';
            turnsHtml += '<span class="tool-name">' + escapeHtml(evt.tool_name || 'unknown') + '</span>';
            turnsHtml += '<span class="tool-meta">' + (evt.success === false ? 'failed' : 'ok') + elapsedStr + '</span></div>';
            if (evt.tool_args) {
              turnsHtml += '<details class="tool-section"><summary>Arguments</summary><pre>' + renderToolArgs(evt.tool_args) + '</pre></details>';
            }
            if (evt.result) {
              turnsHtml += '<details class="tool-section"><summary>Result</summary><pre>' + escapeHtml(evt.result) + '</pre></details>';
            }
            turnsHtml += '</div>';
          }
        }
        turnsHtml += '<div class="timestamp">' + escapeHtml(timeStr) + '</div></div>';
      } else {
        var output = extractOutputFallback(trace.output);
        if (output) {
          turnsHtml += '<div class="turn assistant"><div class="role-label">Assistant</div><div class="bubble md">' + escapeHtml(output) + '</div><div class="timestamp">' + escapeHtml(timeStr) + '</div></div>';
        }
      }
    }

    return '<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Chat Preview</title>'
      + '<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&display=swap" rel="stylesheet">'
      + '<script>'
      + 'function simpleMd(t){'
      + '  t=t.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");'
      + '  var blocks=t.split(/\\n{2,}/);'
      + '  return blocks.map(function(b){'
      + '    b=b.trim(); if(!b) return "";'
      // code blocks
      + '    if(/^```/.test(b)){'
      + '      var m=b.match(/^```[^\\n]*\\n([\\s\\S]*?)(?:```|$)/);'
      + '      return "<pre><code>"+(m?m[1]:b.replace(/^```[^\\n]*/,"").replace(/```$/,""))+"</code></pre>";'
      + '    }'
      // tables
      + '    var lines=b.split("\\n");'
      + '    if(lines.length>=2 && /^\\|/.test(lines[0]) && /^[\\s|:-]+$/.test(lines[1])){'
      + '      var hdr=lines[0].split("|").filter(function(c){return c.trim()!==""}); '
      + '      var html="<table><thead><tr>"+hdr.map(function(c){return "<th>"+inl(c.trim())+"</th>"}).join("")+"</tr></thead><tbody>";'
      + '      for(var r=2;r<lines.length;r++){'
      + '        var cols=lines[r].split("|").filter(function(c){return c.trim()!==""});'
      + '        html+="<tr>"+cols.map(function(c){return "<td>"+inl(c.trim())+"</td>"}).join("")+"</tr>";'
      + '      }'
      + '      return html+"</tbody></table>";'
      + '    }'
      // headings
      + '    if(/^#{1,6}\\s/.test(b)){'
      + '      var lvl=b.match(/^(#+)/)[1].length;'
      + '      return "<h"+lvl+">"+inl(b.replace(/^#+\\s*/,""))+"</h"+lvl+">";'
      + '    }'
      // unordered list
      + '    if(/^[-*]\\s/.test(lines[0])){'
      + '      return "<ul>"+lines.map(function(l){return "<li>"+inl(l.replace(/^[-*]\\s*/,""))+"</li>"}).join("")+"</ul>";'
      + '    }'
      // ordered list
      + '    if(/^\\d+\\.\\s/.test(lines[0])){'
      + '      return "<ol>"+lines.map(function(l){return "<li>"+inl(l.replace(/^\\d+\\.\\s*/,""))+"</li>"}).join("")+"</ol>";'
      + '    }'
      // blockquote
      + '    if(/^&gt;\\s?/.test(b)){'
      + '      return "<blockquote>"+inl(b.replace(/^&gt;\\s?/gm,""))+"</blockquote>";'
      + '    }'
      // paragraph (handle single newlines as <br>)
      + '    return "<p>"+inl(b).replace(/\\n/g,"<br>")+"</p>";'
      + '  }).join("");'
      + '}'
      // inline formatting
      + 'function inl(s){'
      + '  s=s.replace(/`([^`]+)`/g,"<code>$1</code>");'
      + '  s=s.replace(/\\*\\*([^*]+)\\*\\*/g,"<strong>$1</strong>");'
      + '  s=s.replace(/\\*([^*]+)\\*/g,"<em>$1</em>");'
      + '  s=s.replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g,"<a href=\\"$2\\">$1</a>");'
      + '  return s;'
      + '}'
      + '<\/script>'
      + '<style>'
      + '*{margin:0;padding:0;box-sizing:border-box}'
      + ':root{--bg:#111113;--surface:#1a1a1f;--border:#2a2a32;--text:#e4e4e7;--muted:#71717a;--accent:#4d8eff;--user-bg:#2563eb;--user-text:#fff;--asst-bg:#1a1a1f;--asst-text:#e4e4e7;--r:12px;--tool-bg:#0f0f12;--tool-border:#25252d;--tool-ok:#34d399;--tool-fail:#ef4444}'
      + 'html,body{height:100%;background:var(--bg);color:var(--text);font-family:Inter,system-ui,sans-serif;-webkit-font-smoothing:antialiased}'
      + '#app{display:flex;flex-direction:column;height:100%;max-width:860px;margin:0 auto}'
      + 'header{padding:16px 24px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;flex-shrink:0}'
      + 'header h1{font-size:15px;font-weight:600}header .meta{font-size:12px;color:var(--muted);margin-top:2px}'
      + 'header .back{color:var(--accent);text-decoration:none;font-size:13px;font-weight:500;cursor:pointer}'
      + '#chat{flex:1;overflow-y:auto;padding:24px;display:flex;flex-direction:column;gap:20px;scrollbar-width:thin;scrollbar-color:#2a2a32 transparent}'
      + '#chat::-webkit-scrollbar{width:6px}#chat::-webkit-scrollbar-thumb{background:#2a2a32;border-radius:3px}'
      + '.turn{display:flex;flex-direction:column;gap:6px}'
      + '.turn .role-label{font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);padding:0 4px}'
      + '.turn.user .role-label{text-align:right}'
      + '.bubble{max-width:75%;padding:12px 16px;border-radius:var(--r);font-size:14px;line-height:1.65;word-break:break-word}'
      + '.turn.user .bubble{align-self:flex-end;background:var(--user-bg);color:var(--user-text);border-bottom-right-radius:4px}'
      + '.turn.assistant .bubble{align-self:flex-start;background:var(--asst-bg);color:var(--asst-text);border-bottom-left-radius:4px;border:1px solid var(--border)}'
      + '.bubble p{margin:0 0 8px}.bubble p:last-child{margin-bottom:0}'
      + '.bubble code{background:rgba(255,255,255,.08);padding:1px 5px;border-radius:4px;font-size:13px}'
      + '.bubble pre{background:rgba(0,0,0,.35);padding:10px 12px;border-radius:8px;overflow-x:auto;margin:8px 0;font-size:13px}'
      + '.bubble pre code{background:none;padding:0}'
      + '.bubble ul,.bubble ol{padding-left:20px;margin:6px 0}.bubble strong{font-weight:600}.bubble a{color:var(--accent)}'
      + '.bubble blockquote{border-left:3px solid var(--accent);padding-left:12px;margin:8px 0;color:var(--muted)}'
      + '.bubble h1,.bubble h2,.bubble h3{margin:10px 0 6px;font-weight:600}'
      + '.bubble h1{font-size:18px}.bubble h2{font-size:16px}.bubble h3{font-size:15px}'
      + '.bubble table{border-collapse:collapse;margin:8px 0;width:100%}'
      + '.bubble th,.bubble td{border:1px solid var(--border);padding:6px 10px;font-size:13px;text-align:left}'
      + '.bubble th{background:rgba(255,255,255,.05);font-weight:600}'
      + '.timestamp{font-size:11px;color:var(--muted);padding:0 4px}.turn.user .timestamp{text-align:right}'
      + '.divider{display:flex;align-items:center;gap:12px;padding:8px 0;color:var(--muted);font-size:11px}'
      + '.divider::before,.divider::after{content:"";flex:1;height:1px;background:var(--border)}'
      + '.tool-card{align-self:flex-start;max-width:80%;background:var(--tool-bg);border:1px solid var(--tool-border);border-radius:10px;padding:10px 14px;font-size:13px;margin:4px 0}'
      + '.tool-card.tool-ok{border-left:3px solid var(--tool-ok)}'
      + '.tool-card.tool-fail{border-left:3px solid var(--tool-fail)}'
      + '.tool-header{display:flex;align-items:center;gap:8px;margin-bottom:4px}'
      + '.tool-icon{font-size:14px}'
      + '.tool-ok .tool-icon{color:var(--tool-ok)}'
      + '.tool-fail .tool-icon{color:var(--tool-fail)}'
      + '.tool-name{font-weight:600;color:var(--text);font-size:13px}'
      + '.tool-meta{margin-left:auto;color:var(--muted);font-size:11px}'
      + '.tool-section{margin-top:6px}'
      + '.tool-section summary{cursor:pointer;color:var(--muted);font-size:12px;font-weight:500;user-select:none}'
      + '.tool-section summary:hover{color:var(--text)}'
      + '.tool-section pre{margin-top:4px;background:rgba(0,0,0,.35);padding:8px 10px;border-radius:6px;font-size:12px;line-height:1.5;overflow-x:auto;color:var(--muted);max-height:300px;overflow-y:auto;white-space:pre-wrap;word-break:break-all}'
      + '</style></head><body><div id="app"><header><div><h1>Chat Preview</h1><div class="meta">' + escapeHtml(metaParts.join(' · ')) + '</div></div><a class="back" onclick="window.close()">✕ Close</a></header>'
      + '<div id="chat">' + turnsHtml + '</div></div>'
      + '<script>'
      + 'document.querySelectorAll(".bubble.md").forEach(function(el){'
      + '  try{el.innerHTML=simpleMd(el.textContent||"")}catch(e){}'
      + '});'
      + 'document.getElementById("chat").scrollTop=999999;'
      + '<\/script>'
      + '</body></html>';
  }

  function getApiKeys() {
    var saved = null;
    var pid = getProjectId() || '';
    try { saved = JSON.parse(localStorage.getItem('lf-chat-preview-keys-' + pid) || 'null'); } catch(e) {}
    if (saved && saved.pk && saved.sk) return saved;

    var pk = prompt('Enter Langfuse Public Key (pk-lf-...):\n(Saved for future use)');
    if (!pk) return null;
    var sk = prompt('Enter Langfuse Secret Key (sk-lf-...):');
    if (!sk) return null;
    var keys = { pk: pk.trim(), sk: sk.trim() };
    localStorage.setItem('lf-chat-preview-keys-' + pid, JSON.stringify(keys));
    return keys;
  }

  async function openChatPreview() {
    var sessionId = getSessionId();
    var projectId = getProjectId();
    if (!sessionId || !projectId) { alert('Cannot detect session/project ID'); return; }
    window.open('/chat-preview.html?projectId=' + encodeURIComponent(projectId) + '&sessionId=' + encodeURIComponent(sessionId), '_blank');
  }

  var SVG_ICON = '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M7.9 20A9 9 0 1 0 4 16.1L2 22Z"/><path d="M8 12h.01"/><path d="M12 12h.01"/><path d="M16 12h.01"/></svg>';

  function injectButton() {
    if (!isSessionPage()) return;
    if (document.getElementById(CHAT_PREVIEW_BTN_ID)) return;

    var downloadBtn = document.querySelector('button[title="Download session as JSON"]');
    if (!downloadBtn) return;

    var btn = document.createElement('button');
    btn.id = CHAT_PREVIEW_BTN_ID;
    btn.title = 'Chat Preview';
    btn.innerHTML = SVG_ICON;
    btn.className = downloadBtn.className;
    btn.style.cssText = downloadBtn.style.cssText;
    btn.onclick = openChatPreview;

    downloadBtn.parentNode.insertBefore(btn, downloadBtn);
  }

  setInterval(injectButton, CHECK_INTERVAL);
  injectButton();
  window.addEventListener('popstate', function() { setTimeout(injectButton, 500); });

  var observer = new MutationObserver(function() {
    if (isSessionPage() && !document.getElementById(CHAT_PREVIEW_BTN_ID)) {
      injectButton();
    }
  });
  observer.observe(document.body, { childList: true, subtree: true });
})();
